def generate_final_strategy_pdf(state):
    """生成最终投资策略PDF"""
    file_name = f"最终投资策略_{datetime.now().strftime('%Y%m%d%H%M%S')}"
    final_strategy_markdown = state.get("final_strategy_markdown")
    final_strategy_pdf = markdown2pdf(file_name, final_strategy_markdown)

    # 更新思考过程
    thoughts = state.get("thoughts", [])
    thoughts.append("生成最终投资策略 PDF")

    # 更新状态，传递给下一个节点
    return {"file": state.get('file'), "final_strategy_pdf": final_strategy_pdf, "thoughts": thoughts}
